package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.InOrder;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

class GsonNewJsonWriterTest {

  private Gson gson;
  private Writer writer;

  private static final String JSON_NON_EXECUTABLE_PREFIX;

  static {
    String prefix;
    try {
      Field prefixField = Gson.class.getDeclaredField("JSON_NON_EXECUTABLE_PREFIX");
      prefixField.setAccessible(true);
      prefix = (String) prefixField.get(null);
    } catch (Exception e) {
      prefix = null;
    }
    JSON_NON_EXECUTABLE_PREFIX = prefix;
  }

  @BeforeEach
  void setUp() {
    gson = new Gson();
    writer = spy(new StringWriter());
  }

  @Test
  void newJsonWriter_defaultSettings_noPrefixWritten() throws IOException {
    setField(gson, "generateNonExecutableJson", false);
    setField(gson, "prettyPrinting", false);
    setField(gson, "htmlSafe", true);
    setField(gson, "lenient", false);
    setField(gson, "serializeNulls", false);

    JsonWriter jsonWriter = gson.newJsonWriter(writer);

    // Verify no prefix written
    verify(writer, never()).write(JSON_NON_EXECUTABLE_PREFIX);

    // Verify JsonWriter settings
    assertNotNull(jsonWriter);
    assertNull(getIndent(jsonWriter));
    assertTrue(jsonWriter.isHtmlSafe());
    assertFalse(jsonWriter.isLenient());
    assertFalse(getSerializeNulls(jsonWriter));
  }

  @Test
  void newJsonWriter_generateNonExecutableJson_prefixWritten() throws IOException {
    setField(gson, "generateNonExecutableJson", true);
    setField(gson, "prettyPrinting", false);
    setField(gson, "htmlSafe", false);
    setField(gson, "lenient", true);
    setField(gson, "serializeNulls", true);

    JsonWriter jsonWriter = gson.newJsonWriter(writer);

    // Verify prefix is written exactly once
    InOrder inOrder = inOrder(writer);
    inOrder.verify(writer).write(JSON_NON_EXECUTABLE_PREFIX);

    // Verify JsonWriter settings
    assertNotNull(jsonWriter);
    assertNull(getIndent(jsonWriter));
    assertFalse(jsonWriter.isHtmlSafe());
    assertTrue(jsonWriter.isLenient());
    assertTrue(getSerializeNulls(jsonWriter));
  }

  @Test
  void newJsonWriter_prettyPrinting_setsIndent() throws IOException {
    setField(gson, "generateNonExecutableJson", false);
    setField(gson, "prettyPrinting", true);
    setField(gson, "htmlSafe", false);
    setField(gson, "lenient", true);
    setField(gson, "serializeNulls", true);

    JsonWriter jsonWriter = gson.newJsonWriter(writer);

    assertNotNull(jsonWriter);
    assertEquals("  ", getIndent(jsonWriter));
    assertFalse(jsonWriter.isHtmlSafe());
    assertTrue(jsonWriter.isLenient());
    assertTrue(getSerializeNulls(jsonWriter));
  }

  // Utility method to set private final fields via reflection
  private static void setField(Object target, String fieldName, Object value) {
    try {
      Field field = Gson.class.getDeclaredField(fieldName);
      field.setAccessible(true);

      // Remove final modifier if present
      Field modifiersField = Field.class.getDeclaredField("modifiers");
      modifiersField.setAccessible(true);
      modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

      field.set(target, value);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Reflection helper to get indent from JsonWriter
  private static String getIndent(JsonWriter jsonWriter) {
    try {
      Field indentField = JsonWriter.class.getDeclaredField("indent");
      indentField.setAccessible(true);
      return (String) indentField.get(jsonWriter);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }

  // Reflection helper to get serializeNulls from JsonWriter
  private static boolean getSerializeNulls(JsonWriter jsonWriter) {
    try {
      Field serializeNullsField = JsonWriter.class.getDeclaredField("serializeNulls");
      serializeNullsField.setAccessible(true);
      return serializeNullsField.getBoolean(jsonWriter);
    } catch (Exception e) {
      throw new RuntimeException(e);
    }
  }
}
